const CursorItem = ({
  label = "",
  position = "right",
}: {
  label: string
  position?: "left" | "right"
}) => {
  return (
    <motion.div
      className={`flex flex-col ${
        position === "right" ? "items-end" : "items-start"
      }`}
    >
      <div
        className={`mb-1 ${
          position === "left" ? "-ml-[0.8rem]" : "-mr-[0.8rem]"
        }`}
      >
        {position === "left" ? <CursorIconLeft /> : <CursorIconRight />}
      </div>
      <div className="rounded border border-zinc-300 p-2 text-center font-light text-zinc-300 xs:text-xs md:text-base">
        {label}
      </div>
    </motion.div>
  )
}

